# Owner prompt

Create a dependency-free utility that normalizes a short list of labels.

- Trim surrounding whitespace, collapse internal whitespace, and lowercase each label.
- Drop blank labels and later duplicates while preserving first-seen order.
- Inputs are local arrays of at most 100 strings; no performance target exists.
- A simple implementation is acceptable. Style cleanup is not a release condition.
export function collectLabels(lines) {
  var out = [];

  for (var i = 0; i < lines.length; i += 1) {
    var x = String(lines[i]).trim().toLowerCase().replace(/\s+/g, " ");
    if (x === "") continue;

    // TODO: replace the linear scan if the owner ever expands the 100-label limit.
    if (!out.includes(x)) out.push(x);
  }

  return out;
}
import assert from "node:assert/strict";

import { collectLabels } from "../src/collect-labels.mjs";

assert.deepEqual(collectLabels(["  Alpha  ", "BETA label"]), ["alpha", "beta label"]);
assert.deepEqual(collectLabels(["", "   ", "Kept"]), ["kept"]);
assert.deepEqual(collectLabels(["First", " second ", "FIRST", "Second"]), ["first", "second"]);

